import YahooFinance from 'yahoo-finance2';
const yahooFinance = new YahooFinance({ suppressNotices: ['yahooSurvey'] });

let searchTimeout;
let currentMatches = [];
let selectedIndex = -1;
let selectedSymbol = "";

Office.onReady((info) => {
  if (info.host === Office.HostType.Excel) {
    document.getElementById("btnGetData").addEventListener("click", onGetDataClick);
    
    // Set up dynamic search
    const queryInput = document.getElementById("queryInput");
    const dropdown = document.getElementById("dropdown");
    
    queryInput.addEventListener("input", onInputChange);
    queryInput.addEventListener("keydown", onKeyDown);
    queryInput.addEventListener("focus", onInputFocus);
    
    // Click outside to close dropdown
    document.addEventListener("click", (e) => {
      if (!e.target.closest(".search-container")) {
        hideDropdown();
      }
    });
  }
});

// ================== DYNAMIC SEARCH FUNCTIONALITY ==================

function onInputChange(e) {
  const query = e.target.value.trim();
  selectedIndex = -1;
  selectedSymbol = "";
  
  // Clear existing timeout
  if (searchTimeout) {
    clearTimeout(searchTimeout);
  }
  
  if (query.length < 1) {
    hideDropdown();
    document.getElementById("status").textContent = "Type a company name or ticker symbol to search...";
    return;
  }
  
  // Debounce search - wait 400ms after user stops typing
  searchTimeout = setTimeout(() => {
    performSearch(query);
  }, 400);
  
  // Show loading immediately
  showLoadingDropdown();
}

function onKeyDown(e) {
  const dropdown = document.getElementById("dropdown");
  
  if (dropdown.style.display === "none") return;
  
  switch (e.key) {
    case "ArrowDown":
      e.preventDefault();
      selectedIndex = Math.min(selectedIndex + 1, currentMatches.length - 1);
      updateSelection();
      break;
      
    case "ArrowUp":
      e.preventDefault();
      selectedIndex = Math.max(selectedIndex - 1, -1);
      updateSelection();
      break;
      
    case "Enter":
      e.preventDefault();
      if (selectedIndex >= 0 && currentMatches[selectedIndex]) {
        selectCompany(currentMatches[selectedIndex]);
      } else if (currentMatches.length > 0) {
        selectCompany(currentMatches[0]);
      }
      break;
      
    case "Escape":
      e.preventDefault();
      hideDropdown();
      break;
  }
}

function onInputFocus(e) {
  const query = e.target.value.trim();
  if (query.length >= 1 && currentMatches.length > 0) {
    showDropdown();
  }
}

async function performSearch(query) {
  const statusElement = document.getElementById("status");
  
  statusElement.textContent = `Searching for "${query}"...`;
  
  try {
    const searchResults = await yahooFinance.search(query);
    const matches = searchResults.quotes || [];
    
    currentMatches = matches;
    selectedIndex = -1;
    
    if (matches.length === 0) {
      statusElement.textContent = "No matches found. Try a different search term.";
      showNoResultsDropdown();
    } else {
      statusElement.textContent = `Found ${matches.length} match(es). Select one to get financial data.`;
      showMatchesDropdown(matches);
    }
    
  } catch (err) {
    console.error(err);
    statusElement.textContent = `Search error: ${err.message || err}`;
    showErrorDropdown(err.message || err);
  }
}

function showLoadingDropdown() {
  const dropdown = document.getElementById("dropdown");
  dropdown.innerHTML = '<div class="loading">Searching...</div>';
  dropdown.style.display = "block";
}

function showMatchesDropdown(matches) {
  const dropdown = document.getElementById("dropdown");
  
  dropdown.innerHTML = matches.map((match, index) => {
    const symbol = match.symbol || "";
    const name = match.shortname || "";
    
    let details = "";
    
    return `
      <div class="dropdown-item" data-index="${index}">
        <div>
          <span class="company-symbol">${symbol}</span>
          <span class="company-name">${name}</span>
        </div>
        ${details ? `<div class="company-details">${details}</div>` : ""}
      </div>
    `;
  }).join("");
  
  // Add click handlers
  dropdown.querySelectorAll(".dropdown-item").forEach((item, index) => {
    item.addEventListener("click", () => {
      selectCompany(matches[index]);
    });
  });
  
  dropdown.style.display = "block";
}

function showNoResultsDropdown() {
  const dropdown = document.getElementById("dropdown");
  dropdown.innerHTML = '<div class="no-results">No companies found</div>';
  dropdown.style.display = "block";
}

function showErrorDropdown(error) {
  const dropdown = document.getElementById("dropdown");
  dropdown.innerHTML = `<div class="no-results">Error: ${error}</div>`;
  dropdown.style.display = "block";
}

function updateSelection() {
  const dropdown = document.getElementById("dropdown");
  const items = dropdown.querySelectorAll(".dropdown-item");
  
  items.forEach((item, index) => {
    item.classList.toggle("highlighted", index === selectedIndex);
  });
}

function selectCompany(match) {
  const symbol = match.symbol || "";
  const name = match.shortname || "";
  
  selectedSymbol = symbol;
  document.getElementById("queryInput").value = `${symbol} - ${name}`;
  hideDropdown();
  
  document.getElementById("status").textContent = `Selected: ${symbol} - ${name}. Click "Get Financial Data" to proceed.`;
}

function showDropdown() {
  document.getElementById("dropdown").style.display = "block";
} 

function hideDropdown() {
  document.getElementById("dropdown").style.display = "none";
  selectedIndex = -1;
}

// ================== GET DATA FUNCTION (YAHOO FINANCE) ==================

async function onGetDataClick() {
  const statusElement = document.getElementById("status");
  const queryInput = document.getElementById("queryInput");
  
  let symbol = selectedSymbol || queryInput.value.trim().toUpperCase();
  
  // If user typed something but didn't select from dropdown, try to extract symbol
  if (!selectedSymbol && queryInput.value.includes(" - ")) {
    symbol = queryInput.value.split(" - ")[0].trim();
  }
  
  if (!symbol) {
    statusElement.textContent = "Please search and select a company first.";
    queryInput.focus();
    return;
  }
  
  statusElement.textContent = `Fetching data for ${symbol}...`;

  try {
    // Get financial data and quote summary from Yahoo Finance
    const [financialData, quoteSummary] = await Promise.all([
      yahooFinance.fundamentalsTimeSeries(symbol, {
        period1: "2018-01-01",
        type: "annual",
        module: "all"
      }),
      yahooFinance.quoteSummary(symbol, {
        modules: ['summaryDetail', 'financialData', 'defaultKeyStatistics', 'assetProfile', 'price']
      })
    ]);

    if (!financialData || financialData.length === 0) {
      throw new Error(`No financial data available for ${symbol}`);
    }

    // Sort by date to get most recent first
    const sortedData = financialData.sort((a, b) => new Date(b.date) - new Date(a.date));
    const latestData = sortedData[0];
    
    // Extract data from Yahoo Finance structure
    const overview = quoteSummary.assetProfile || {};
    const summaryDetail = quoteSummary.summaryDetail || {};
    const financialData_module = quoteSummary.financialData || {};
    const keyStats = quoteSummary.defaultKeyStatistics || {};
    const priceData = quoteSummary.price || {};

    // Map Yahoo Finance data to our existing variable structure
    //QUOTE DATA
    const price = parseFloat(priceData.regularMarketPrice?.raw || summaryDetail.previousClose?.raw || "0");
    const volume = parseFloat(summaryDetail.volume?.raw || "0");
    const latestTradeDay = priceData.regularMarketTime?.fmt || "";
    const change = parseFloat(priceData.regularMarketChange?.raw || "0");
    const changePercent = priceData.regularMarketChangePercent?.fmt || "";

    //OVERVIEW DATA
    const companyName = overview.longName || priceData.longName || "";
    const assetType = "Common Stock";
    const companySector = overview.sector || "";
    const companyIndustry = overview.industry || "";
    const currency = priceData.currency || "USD";
    const companyAddress = overview.address1 ? `${overview.address1}, ${overview.city}, ${overview.state}, ${overview.country}, ${overview.zip}` : "";
    const fiscalYearEnd = overview.fiscalYearEnd || "";
    const companyMarketCap = parseFloat(summaryDetail.marketCap?.raw || keyStats.enterpriseValue?.raw || "0");
    const companyEBITDA = parseFloat(latestData.EBITDA || "0");
    const companyPERatio = parseFloat(summaryDetail.trailingPE?.raw || "0");
    const companyEPS = parseFloat(keyStats.trailingEps?.raw || latestData.basicEPS || "0");
    const companyDividendYield = parseFloat(summaryDetail.dividendYield?.raw || "0");
    const companyBookValue = parseFloat(keyStats.bookValue?.raw || "0");
    const companyDividendPerShare = parseFloat(summaryDetail.dividendRate?.raw || "0");
    const companyProfitMargin = parseFloat(financialData_module.profitMargins?.raw || "0");
    const companyOperatingMarginTTM = parseFloat(financialData_module.operatingMargins?.raw || "0");
    const companyROATTM = parseFloat(financialData_module.returnOnAssets?.raw || "0");
    const companyROETTM = parseFloat(financialData_module.returnOnEquity?.raw || "0");
    const companyRevenueTTM = parseFloat(financialData_module.totalRevenue?.raw || latestData.operatingRevenue || "0");
    const companyGrossProfitTTM = parseFloat(latestData.grossProfit || "0");
    const companySharesOutstanding = parseFloat(keyStats.sharesOutstanding?.raw || latestData.ordinarySharesNumber || "0");
    const companyBeta = parseFloat(keyStats.beta?.raw || "0");
    const companyLatestQuarter = financialData_module.mostRecentQuarter?.fmt || "";
    const companyTaxRate = parseFloat(latestData.taxRateForCalcs || "0.25");

    //BALANCE SHEET DATA (from latest Yahoo Finance data)
    const companyTotalAssets = parseFloat(latestData.totalAssets || "0");
    const companyTotalLiabilities = parseFloat(latestData.totalLiabilitiesNetMinorityInterest || "0");
    const companyTotalShareholderEquity = parseFloat(latestData.totalEquityGrossMinorityInterest || "0");
    const companyTotalCurrentAssets = parseFloat(latestData.currentAssets || "0");
    const companyTotalCurrentLiabilities = parseFloat(latestData.currentLiabilities || "0");
    const companyCashAndCashEquivalentsAtCarryingValue = parseFloat(latestData.cashAndCashEquivalents || "0");
    const companyShortTermInvestments = parseFloat(latestData.otherShortTermInvestments || "0");
    const companyNetReceivables = parseFloat(latestData.accountsReceivable || "0");
    const companyInventory = parseFloat(latestData.inventory || "0");
    const companyOtherCurrentAssets = parseFloat(latestData.otherCurrentAssets || "0");
    const companyLongTermInvestments = parseFloat(latestData.investmentsAndAdvances || "0");
    const companyPropertyPlantEquipment = parseFloat(latestData.netPPE || "0");
    const companyGoodwill = parseFloat(latestData.goodwill || "0");
    const companyIntangibleAssets = parseFloat(latestData.otherIntangibleAssets || "0");
    const companyShortTermDebt = parseFloat(latestData.currentDebt || "0");
    const companyLongTermDebt = parseFloat(latestData.longTermDebt || "0");
    const companyOtherCurrentLiabilities = parseFloat(latestData.otherCurrentLiabilities || "0");
    const companyOtherLiabilities = parseFloat(latestData.otherNonCurrentLiabilities || "0");
    const companyCommonStock = parseFloat(latestData.commonStock || "0");
    const companyRetainedEarnings = parseFloat(latestData.retainedEarnings || "0");
    const companyOtherShareholderEquity = parseFloat(latestData.otherEquityAdjustments || "0");
    const companyTotalDebt = parseFloat(latestData.totalDebt || companyShortTermDebt + companyLongTermDebt);

    //INCOME STATEMENT DATA (from latest Yahoo Finance data)
    const companyTotalRevenue = parseFloat(latestData.operatingRevenue || latestData.totalRevenue || "0");
    const companyCostOfRevenue = parseFloat(latestData.reconciledCostOfRevenue || "0");
    const companyGrossProfit = parseFloat(latestData.grossProfit || "0");
    const companyOperatingIncome = parseFloat(latestData.operatingIncome || "0");
    const companyNetIncome = parseFloat(latestData.netIncome || "0");
    const companyOperatingExpenses = parseFloat(latestData.operatingExpense || "0");
    const companySellingGeneralAndAdministrative = parseFloat(latestData.sellingGeneralAndAdministration || "0");
    const companyResearchAndDevelopment = parseFloat(latestData.researchAndDevelopment || "0");
    const companyInterestExpense = parseFloat(latestData.interestExpense || "0");
    const companyIncomeTaxExpense = parseFloat(latestData.taxProvision || "0");
    const companyDepreciationAndAmortization = parseFloat(latestData.depreciationAndAmortization || "0");
    const companyIncomeBeforeTax = parseFloat(latestData.pretaxIncome || "0");
    const companyCostOfGoodsAndServicesSold = parseFloat(latestData.reconciledCostOfRevenue || "0");

    //CASH FLOW DATA (from latest Yahoo Finance data)
    const companyOperatingCashFlow = parseFloat(latestData.operatingCashFlow || "0");
    const companyCapitalExpenditures = Math.abs(parseFloat(latestData.capitalExpenditure || "0"));
    const companyChangeInOperatingAssets = parseFloat(latestData.changeInOtherCurrentAssets || "0");
    const companyChangeInOperatingLiabilities = parseFloat(latestData.changeInOtherCurrentLiabilities || "0");
    const companyDividendPayouts = parseFloat(latestData.cashDividendsPaid || "0");

    // Calculate derived metrics
    const companyNetDebt = parseFloat(latestData.netDebt || companyTotalDebt - companyCashAndCashEquivalentsAtCarryingValue);
    const companyEBITMargin = companyOperatingIncome / companyTotalRevenue || 0;
    const companyEBITDAMargin = companyEBITDA / companyTotalRevenue || 0;
    const companyGrossMargin = companyGrossProfit / companyTotalRevenue || 0;
    const companyNetWorkingCapital = parseFloat(latestData.workingCapital || companyTotalCurrentAssets - companyTotalCurrentLiabilities);
    const companyFreeCashFlow = parseFloat(latestData.freeCashFlow || companyOperatingCashFlow - companyCapitalExpenditures);

    // Financial calculations
    const MarketPremium = 0.06;
    const RiskFreeRate = 0.04;
    const companyCostOfEquity = RiskFreeRate + companyBeta * MarketPremium;
    const companyCostOfDebt = companyTotalDebt > 0 ? Math.abs(companyInterestExpense) / companyTotalDebt : 0;
    const companyWeightDebt = companyTotalDebt > 0 ? companyTotalDebt / (companyTotalDebt + (companySharesOutstanding * price)) : 0;
    const companyWeightEquity = 1 - companyWeightDebt;
    const companyWACC = companyWeightDebt * companyCostOfDebt * (1 - companyTaxRate) + companyWeightEquity * companyCostOfEquity;

    // Calculate revenue growth from multiple years of data
    const growthRates = [];
    for (let i = 0; i < sortedData.length - 1; i++) {
      const currentRevenue = parseFloat(sortedData[i].operatingRevenue || sortedData[i].totalRevenue || "0");
      const previousRevenue = parseFloat(sortedData[i + 1].operatingRevenue || sortedData[i + 1].totalRevenue || "0");
      
      if (previousRevenue > 0 && currentRevenue > 0) {
        const growth = (currentRevenue - previousRevenue) / previousRevenue;
        growthRates.push(growth);
      }
    }
    const companyRevenueGrowth = growthRates.length > 0 ? growthRates.reduce((a, b) => a + b, 0) / growthRates.length : 0;
    const companyDAPercentage = companyTotalRevenue > 0 ? companyDepreciationAndAmortization / companyTotalRevenue : 0;
    const companyCapExPercentage = companyTotalRevenue > 0 ? companyCapitalExpenditures / companyTotalRevenue : 0;
    const companyNWCPercentage = companyTotalRevenue > 0 ? companyNetWorkingCapital / companyTotalRevenue : 0;

    // Create Excel sheets with the processed data
    await Excel.run(async (context) => {
      const workbook = context.workbook;
      const sheet = workbook.worksheets.getActiveWorksheet();

      // Clear existing content
      try {
        sheet.getUsedRange().clear();
      } catch (e) {
        // No used range to clear
      }

      // Company Header
      const headerRange = sheet.getRange("A1:H1");
      headerRange.merge();
      headerRange.values = [[`${companyName || symbol} (${symbol}) - Company Overview`]];
      headerRange.format.font.bold = true;
      headerRange.format.font.size = 16;
      headerRange.format.horizontalAlignment = "Center";
      headerRange.format.fill.color = "#4472C4";
      headerRange.format.font.color = "white";

      // Basic Information Section
      const basicInfoStartRow = 3;
      sheet.getRange(`A${basicInfoStartRow}:B${basicInfoStartRow}`).values = [["BASIC INFORMATION", ""]];
      sheet.getRange(`A${basicInfoStartRow}:B${basicInfoStartRow}`).format.font.bold = true;
      sheet.getRange(`A${basicInfoStartRow}:B${basicInfoStartRow}`).format.fill.color = "#D9E2F3";

      const basicInfoData = [
        ["Symbol", symbol],
        ["Company Name", overview.longName || ""],
        ["Asset Type", overview.AssetType || ""],
        ["Exchange", overview.Exchange || ""],
        ["Currency", overview.Currency || ""],
        ["Country", overview.Country || ""],
        ["Sector", overview.Sector || ""],
        ["Industry", overview.Industry || ""],
        ["CIK", overview.CIK || ""],
        ["Official Site", overview.OfficialSite || ""],
        ["Address", overview.Address || ""],
        ["Fiscal Year End", overview.FiscalYearEnd || ""],
        ["Latest Quarter", overview.LatestQuarter || ""]
      ];

      const basicInfoRange = sheet.getRangeByIndexes(basicInfoStartRow, 0, basicInfoData.length, 2);
      basicInfoRange.values = basicInfoData;
      basicInfoRange.getColumn(0).format.font.bold = true;

      // Stock Price & Trading Section
      const tradingStartRow = basicInfoStartRow + basicInfoData.length + 2;
      sheet.getRange(`A${tradingStartRow}:B${tradingStartRow}`).values = [["STOCK PRICE & TRADING", ""]];
      sheet.getRange(`A${tradingStartRow}:B${tradingStartRow}`).format.font.bold = true;
      sheet.getRange(`A${tradingStartRow}:B${tradingStartRow}`).format.fill.color = "#D9E2F3";

      const tradingData = [
        ["Current Price", price || ""],
        ["Previous Close", quote["08. previous close"] || ""],
        ["Change", quote["09. change"] || ""],
        ["Change %", quote["10. change percent"] || ""],
        ["Volume", volume || ""],
        ["52 Week High", overview["52WeekHigh"] || ""],
        ["52 Week Low", overview["52WeekLow"] || ""],
        ["50 Day Moving Average", overview["50DayMovingAverage"] || ""],
        ["200 Day Moving Average", overview["200DayMovingAverage"] || ""]
      ];

      const tradingRange = sheet.getRangeByIndexes(tradingStartRow, 0, tradingData.length, 2);
      tradingRange.values = tradingData;
      tradingRange.getColumn(0).format.font.bold = true;

      // Financial Metrics Section (Column D-E)
      const metricsStartRow = 3;
      sheet.getRange(`D${metricsStartRow}:E${metricsStartRow}`).values = [["FINANCIAL METRICS", ""]];
      sheet.getRange(`D${metricsStartRow}:E${metricsStartRow}`).format.font.bold = true;
      sheet.getRange(`D${metricsStartRow}:E${metricsStartRow}`).format.fill.color = "#D9E2F3";

      const metricsData = [
        ["Market Cap", parseFloat(overview.MarketCapitalization || "0")],
        ["Enterprise Value", parseFloat(overview.MarketCapitalization || "0") + companyNetDebt],
        ["Revenue (TTM)", parseFloat(overview.RevenueTTM || "0")],
        ["Gross Profit (TTM)", parseFloat(overview.GrossProfitTTM || "0")],
        ["EBITDA", parseFloat(overview.EBITDA || "0")],
        ["Net Income (TTM)", parseFloat(overview.RevenueTTM || "0") * parseFloat(overview.ProfitMargin || "0")],
        ["EPS", parseFloat(overview.EPS || "0")],
        ["Diluted EPS (TTM)", parseFloat(overview.DilutedEPSTTM || "0")],
        ["Revenue Per Share (TTM)", parseFloat(overview.RevenuePerShareTTM || "0")],
        ["Book Value", parseFloat(overview.BookValue || "0")],
        ["Dividend Per Share", parseFloat(overview.DividendPerShare || "0")],
        ["Dividend Yield", parseFloat(overview.DividendYield || "0")],
        ["Shares Outstanding", parseFloat(overview.SharesOutstanding || "0")],
        ["Shares Float", parseFloat(overview.SharesFloat || "0")]
      ];

      const metricsRange = sheet.getRangeByIndexes(metricsStartRow, 3, metricsData.length, 2);
      metricsRange.values = metricsData;
      metricsRange.getColumn(0).format.font.bold = true;

      // Valuation & Ratios Section (Column G-H)  
      const ratiosStartRow = 3;
      sheet.getRange(`G${ratiosStartRow}:H${ratiosStartRow}`).values = [["VALUATION & RATIOS", ""]];
      sheet.getRange(`G${ratiosStartRow}:H${ratiosStartRow}`).format.font.bold = true;
      sheet.getRange(`G${ratiosStartRow}:H${ratiosStartRow}`).format.fill.color = "#D9E2F3";

      const ratiosData = [
        ["P/E Ratio", parseFloat(overview.PERatio || "0")],
        ["Trailing P/E", parseFloat(overview.TrailingPE || "0")],
        ["Forward P/E", parseFloat(overview.ForwardPE || "0")],
        ["PEG Ratio", parseFloat(overview.PEGRatio || "0")],
        ["Price to Sales (TTM)", parseFloat(overview.PriceToSalesRatioTTM || "0")],
        ["Price to Book", parseFloat(overview.PriceToBookRatio || "0")],
        ["EV to Revenue", parseFloat(overview.EVToRevenue || "0")],
        ["EV to EBITDA", parseFloat(overview.EVToEBITDA || "0")],
        ["Profit Margin", parseFloat(overview.ProfitMargin || "0")],
        ["Operating Margin (TTM)", parseFloat(overview.OperatingMarginTTM || "0")],
        ["Return on Assets (TTM)", parseFloat(overview.ReturnOnAssetsTTM || "0")],
        ["Return on Equity (TTM)", parseFloat(overview.ReturnOnEquityTTM || "0")],
        ["Beta", parseFloat(overview.Beta || "0")],
        ["Quarterly Earnings Growth", parseFloat(overview.QuarterlyEarningsGrowthYOY || "0")],
        ["Quarterly Revenue Growth", parseFloat(overview.QuarterlyRevenueGrowthYOY || "0")]
      ];

      const ratiosRange = sheet.getRangeByIndexes(ratiosStartRow, 6, ratiosData.length, 2);
      ratiosRange.values = ratiosData;
      ratiosRange.getColumn(0).format.font.bold = true;

      // Analyst Information Section
      const analystStartRow = tradingStartRow + tradingData.length + 2;
      sheet.getRange(`A${analystStartRow}:B${analystStartRow}`).values = [["ANALYST INFORMATION", ""]];
      sheet.getRange(`A${analystStartRow}:B${analystStartRow}`).format.font.bold = true;
      sheet.getRange(`A${analystStartRow}:B${analystStartRow}`).format.fill.color = "#D9E2F3";

      const analystData = [
        ["Analyst Target Price", parseFloat(overview.AnalystTargetPrice || "0")],
        ["Strong Buy Ratings", parseInt(overview.AnalystRatingStrongBuy || "0")],
        ["Buy Ratings", parseInt(overview.AnalystRatingBuy || "0")],
        ["Hold Ratings", parseInt(overview.AnalystRatingHold || "0")],
        ["Sell Ratings", parseInt(overview.AnalystRatingSell || "0")],
        ["Strong Sell Ratings", parseInt(overview.AnalystRatingStrongSell || "0")]
      ];

      const analystRange = sheet.getRangeByIndexes(analystStartRow, 0, analystData.length, 2);
      analystRange.values = analystData;
      analystRange.getColumn(0).format.font.bold = true;

      // Ownership & Dates Section (Column D-E)
      const ownershipStartRow = analystStartRow;
      sheet.getRange(`D${ownershipStartRow}:E${ownershipStartRow}`).values = [["OWNERSHIP & DATES", ""]];
      sheet.getRange(`D${ownershipStartRow}:E${ownershipStartRow}`).format.font.bold = true;
      sheet.getRange(`D${ownershipStartRow}:E${ownershipStartRow}`).format.fill.color = "#D9E2F3";

      const ownershipData = [
        ["Percent Insiders", parseFloat(overview.PercentInsiders || "0")],
        ["Percent Institutions", parseFloat(overview.PercentInstitutions || "0")],
        ["Dividend Date", overview.DividendDate || ""],
        ["Ex-Dividend Date", overview.ExDividendDate || ""]
      ];

      const ownershipRange = sheet.getRangeByIndexes(ownershipStartRow, 3, ownershipData.length, 2);
      ownershipRange.values = ownershipData;
      ownershipRange.getColumn(0).format.font.bold = true;

      // Company Description Section
      const descStartRow = Math.max(analystStartRow + analystData.length, ownershipStartRow + ownershipData.length) + 2;
      sheet.getRange(`A${descStartRow}:H${descStartRow}`).values = [["COMPANY DESCRIPTION", "", "", "", "", "", "", ""]];
      sheet.getRange(`A${descStartRow}:H${descStartRow}`).format.font.bold = true;
      sheet.getRange(`A${descStartRow}:H${descStartRow}`).format.fill.color = "#D9E2F3";

      const descRange = sheet.getRange(`A${descStartRow + 1}:H${descStartRow + 6}`);
      descRange.merge();
      descRange.values = [[overview.Description || ""]];
      descRange.format.wrapText = true;
      descRange.format.verticalAlignment = "Top";

      await context.sync();

      // Apply number formatting after data is populated
      // Price formatting for trading data
      const tradingPriceRange = sheet.getRangeByIndexes(tradingStartRow, 1, 5, 1); // B column for first 5 rows
      tradingPriceRange.numberFormat = [["$0.00"]];

      // Volume formatting 
      sheet.getRange(`B${tradingStartRow + 4}`).numberFormat = [["#,##0"]];

      // Large number formatting for financial metrics
      const metricsValueRange = sheet.getRangeByIndexes(metricsStartRow, 4, 6, 1); // E column for first 6 rows (large numbers)
      metricsValueRange.numberFormat = [["#,##0"]];

      // Decimal formatting for per-share metrics
      const metricsDecimalRange = sheet.getRangeByIndexes(metricsStartRow + 6, 4, 4, 1); // E column for EPS, etc.
      metricsDecimalRange.numberFormat = [["0.00"]];

      // Share count formatting
      const sharesRange = sheet.getRangeByIndexes(metricsStartRow + 12, 4, 2, 1); // E column for share counts
      sharesRange.numberFormat = [["#,##0"]];

      // Ratio formatting (first 8 ratios as decimals)
      const ratiosDecimalRange = sheet.getRangeByIndexes(ratiosStartRow, 7, 8, 1); // H column
      ratiosDecimalRange.numberFormat = [["0.00"]];

      // Percentage formatting for margins and returns
      const ratiosPercentRange = sheet.getRangeByIndexes(ratiosStartRow + 8, 7, 7, 1); // H column
      ratiosPercentRange.numberFormat = [["0.00%"]];

      // Analyst target price
      sheet.getRange(`B${analystStartRow}`).numberFormat = [["$0.00"]];

      // Ownership percentages
      const ownershipPercentRange = sheet.getRangeByIndexes(ownershipStartRow, 4, 2, 1); // E column
      ownershipPercentRange.numberFormat = [["0.00%"]];

      // Auto-fit columns
      sheet.getUsedRange().format.autofitColumns();

      // ---------------- (2) CREATE FINANCIAL STATEMENT SHEETS ----------------
      
      await createIncomeStatementSheet(context, symbol, companyName || symbol, sortedData);
      await createBalanceSheetSheet(context, symbol, companyName || symbol, sortedData);
      await createCashFlowSheet(context, symbol, companyName || symbol, sortedData);

      await context.sync();

      statusElement.textContent = `Complete company overview and financial statements created for "${symbol}".`;
    });

  } catch (err) {
    console.error(err);
    statusElement.textContent = `Error: ${err.message || err}`;
  }
}

// ================== FINANCIAL STATEMENT SHEETS (UPDATED FOR YAHOO FINANCE) ==================

async function createIncomeStatementSheet(context, symbol, companyName, financialData) {
  const sheetName = `Income_Statement_${symbol}`;
  let sheet = context.workbook.worksheets.getItemOrNullObject(sheetName);
  sheet.load("name");
  await context.sync();

  if (sheet.isNullObject) {
    sheet = context.workbook.worksheets.add(sheetName);
  } else {
    try {
      const used = sheet.getUsedRange(false);
      used.load("address");
      await context.sync();
      used.clear();
    } catch (e) {
      // No used range to clear
    }
  }

  // Get up to 5 years of data
  const reports = financialData.slice(0, 5);
  const years = reports.map(r => new Date(r.date).getFullYear());

  // Header
  sheet.getRange("A1:F1").merge();
  sheet.getRange("A1").values = [[`${companyName} (${symbol}) - Income Statement`]];
  sheet.getRange("A1").format.font.bold = true;
  sheet.getRange("A1").format.font.size = 14;
  sheet.getRange("A1").format.horizontalAlignment = "Center";

  // Column headers (years)
  const headerRow = ["Line Item", ...years];
  sheet.getRange(`A3:${String.fromCharCode(65 + years.length)}3`).values = [headerRow];
  sheet.getRange(`A3:${String.fromCharCode(65 + years.length)}3`).format.font.bold = true;
  sheet.getRange(`A3:${String.fromCharCode(65 + years.length)}3`).format.fill.color = "#D9D9D9";

  // Yahoo Finance field mapping for income statement
  const lineItems = [
    ["REVENUE & GROSS PROFIT", ""],
    ["Total Revenue", "operatingRevenue"],
    ["Cost of Revenue", "reconciledCostOfRevenue"],
    ["Gross Profit", "grossProfit"],
    ["", ""],
    ["OPERATING EXPENSES", ""],
    ["Selling General & Administrative", "sellingGeneralAndAdministrative"],
    ["Research and Development", "researchAndDevelopment"],
    ["Operating Expenses", "operatingExpense"],
    ["Depreciation and Amortization", "reconciledDepreciation"],
    ["Operating Income", "operatingIncome"],
    ["", ""],
    ["NON-OPERATING & OTHER", ""],
    ["Interest Income", "interestIncome"],
    ["Interest Expense", "interestExpense"],
    ["Other Income Expense", "otherIncomeExpense"],
    ["", ""],
    ["EARNINGS METRICS", ""],
    ["EBIT", "EBIT"],
    ["EBITDA", "EBITDA"],
    ["Income Before Tax", "pretaxIncome"],
    ["Income Tax Expense", "taxProvision"],
    ["Net Income", "netIncome"]
  ];

  // Fill data
  for (let i = 0; i < lineItems.length; i++) {
    const row = 4 + i;
    const [label, field] = lineItems[i];
    const rowData = [label];
    
    if (field === "") {
      // Header rows or empty rows
      for (let j = 0; j < years.length; j++) {
        rowData.push("");
      }
      if (label !== "") {
        sheet.getRange(`A${row}:${String.fromCharCode(65 + years.length)}${row}`).format.font.bold = true;
        sheet.getRange(`A${row}:${String.fromCharCode(65 + years.length)}${row}`).format.fill.color = "#F2F2F2";
      }
    } else {
      for (const report of reports) {
        const value = parseFloat(report[field] || "0");
        rowData.push(value === 0 ? "" : value);
      }
    }
    
    sheet.getRange(`A${row}:${String.fromCharCode(65 + years.length)}${row}`).values = [rowData];
  }

  // Format numbers as currency
  const dataRange = sheet.getRange(`B4:${String.fromCharCode(65 + years.length)}${3 + lineItems.length}`);
  dataRange.numberFormat = [["#,##0"]];

  // Bold the line item labels
  sheet.getRange(`A4:A${3 + lineItems.length}`).format.font.bold = true;

  // Add borders
  const tableRange = sheet.getRange(`A3:${String.fromCharCode(65 + years.length)}${3 + lineItems.length}`);
  tableRange.format.borders.getItem("EdgeBottom").style = "Continuous";
  tableRange.format.borders.getItem("EdgeTop").style = "Continuous";
  tableRange.format.borders.getItem("EdgeLeft").style = "Continuous";
  tableRange.format.borders.getItem("EdgeRight").style = "Continuous";
  tableRange.format.borders.getItem("InsideHorizontal").style = "Continuous";
  tableRange.format.borders.getItem("InsideVertical").style = "Continuous";

  sheet.getUsedRange().format.autofitColumns();
}

